class Solution:
    def findWords(self, words: List[str]) -> List[str]:
        rows = ["qwertyuiop","asdfghjkl","zxcvbnm"]
        mp = {c: i for i, r in enumerate(rows) for c in r}
        ans = []
        for w in words:
            r0 = mp[w[0].lower()]
            if all(mp[c.lower()] == r0 for c in w):
                ans.append(w)
        return ans

